# --- Helper for publishing jobs (use this from your task producer) ---

def publish_job(project_id, topic_id, job_id, job_type, payload):
    """
    Helper to publish a signed job message to Pub/Sub.
    Use this from your job producer/scheduler.
    """
    from google.cloud import pubsub_v1

    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path(project_id, topic_id)

    job = {
        "job_id": job_id,
        "job_type": job_type,
        "payload": payload,
        "timestamp": datetime.utcnow().isoformat() + "Z",
    }

    message_data = json.dumps(job, default=str).encode("utf-8")

    # Sign the message for integrity verification
    attributes = {}
    signing_key = os.environ.get("MESSAGE_SIGNING_KEY", "").encode("utf-8")
    if signing_key:
        signature = hmac.new(signing_key, message_data, hashlib.sha256).hexdigest()
        attributes["signature"] = signature

    future = publisher.publish(topic_path, data=message_data, **attributes)
    message_id = future.result()
    logger.info(f"Published job {job_id} as message {message_id}")
    return message_id